import{_ as s,o as i,c as t,a3 as o}from"./chunks/framework.LBeL10WQ.js";const g=JSON.parse('{"title":"Logistique & Insertion","description":"","frontmatter":{"title":"Logistique & Insertion"},"headers":[],"relativePath":"publishers/sponsored-mail/logistics.md","filePath":"publishers/sponsored-mail/logistics.md"}'),r={name:"publishers/sponsored-mail/logistics.md"};function a(n,e,l,d,p,u){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="operations-logistiques" tabindex="-1">Opérations Logistiques <a class="header-anchor" href="#operations-logistiques" aria-label="Permalink to &quot;Opérations Logistiques&quot;">​</a></h1><p>De la réception des palettes à l&#39;expérience d&#39;ouverture client (Unboxing).</p><hr><h2 id="_1-reception-des-supports" tabindex="-1">1. Réception des supports <a class="header-anchor" href="#_1-reception-des-supports" aria-label="Permalink to &quot;1. Réception des supports&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Contrôle à l&#39;arrivée</h3><p>Les supports (flyers, échantillons) sont livrés à l&#39;adresse de votre entrepôt renseignée sur la plateforme.</p><ul><li>Vérifiez l&#39;état des palettes et des cartons.</li><li>Vérifiez que la quantité correspond au bon de livraison (BL).</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Confirmation de Réception</h3><p><strong>Action obligatoire :</strong> Connectez-vous sur <a href="https://app.getinside.media/">app.getinside.media</a> et cliquez sur <strong>&quot;Valider la réception&quot;</strong>.</p><p>Cela notifie l&#39;Annonceur que la marchandise est bien arrivée et prête à être distribuée.</p></div></div><div class="warning custom-block"><p class="custom-block-title">Problème de livraison ?</p><p>Si les supports sont endommagés, prenez des photos et signalez-le immédiatement à <a href="mailto:logistique@getinside.fr" target="_blank" rel="noreferrer">logistique@getinside.fr</a> <strong>avant toute distribution</strong>.</p></div><hr><h2 id="_2-bonnes-pratiques-d-insertion" tabindex="-1">2. Bonnes pratiques d&#39;insertion <a class="header-anchor" href="#_2-bonnes-pratiques-d-insertion" aria-label="Permalink to &quot;2. Bonnes pratiques d&#39;insertion&quot;">​</a></h2><p>La valeur de l&#39;Insertion Colis repose sur l&#39;expérience d&#39;ouverture. Pour garantir la satisfaction de l&#39;Annonceur, respectez ces règles d&#39;or.</p><h3 id="✅-la-regle-du-on-top" tabindex="-1">✅ La Règle du &quot;On-Top&quot; <a class="header-anchor" href="#✅-la-regle-du-on-top" aria-label="Permalink to &quot;✅ La Règle du &quot;On-Top&quot;&quot;">​</a></h3><p>Le support publicitaire doit impérativement être déposé <strong>sur les produits</strong>, face visible. Il doit être la première chose que le client voit.</p><p><img src="/handbook/images/asile-colis-do-dont.webp" alt="Bonnes pratiques insertion Insertion Colis"></p><div class="gi-value-grid"><div class="gi-value-card"><strong>📄 Gestion de la facture</strong><p>Si vous insérez un BL ou une facture papier : placez l&#39;offre <strong>au-dessus</strong>. Elle ne doit jamais être cachée à l&#39;intérieur d&#39;un document plié.</p></div><div class="gi-value-card"><strong>🚫 Exclusions &amp; Qualité</strong><ul><li><strong>Concurrence :</strong> Jamais deux offres concurrentes dans le même colis.</li><li><strong>État :</strong> Ne pas insérer de flyer froissé ou corné.</li></ul></div></div><h2 id="_3-stockage" tabindex="-1">3. Stockage <a class="header-anchor" href="#_3-stockage" aria-label="Permalink to &quot;3. Stockage&quot;">​</a></h2><p>Les supports doivent être stockés dans un endroit sec et propre (à l&#39;abri de l&#39;humidité et de la poussière) pour éviter toute détérioration avant insertion.</p>',16)])])}const h=s(r,[["render",a]]);export{g as __pageData,h as default};
